// src/pages/ngo/user/AddExpensePage.jsx
import { useState }  from "react";
import { useToast }  from "../../../context/ToastContext";
import PageHeader    from "../../../components/shared/PageHeader";
import DataTable     from "../../../components/shared/DataTable";
import Badge         from "../../../components/shared/Badge";
import { funds, expenses } from "../../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";
const myFunds = funds.filter((f) => f.ngo === "NGO001");

export default function AddExpensePage() {
  const toast = useToast();
  const [form, setForm] = useState({ fund:"", desc:"", amount:"", cat:"", receipt:"" });
  const upd = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  return (
    <div>
      <PageHeader title="Add Expense" desc="Record a fund expenditure on the blockchain for transparency" />
      <div className="grid-2">
        <div className="card">
          <div className="form-grid section-gap">
            <div className="form-group">
              <label>Fund</label>
              <select value={form.fund} onChange={upd("fund")}>
                <option value="">Select fund...</option>
                {myFunds.map((f) => <option key={f.id} value={f.id}>{f.name}</option>)}
              </select>
            </div>
            <div className="form-group"><label>Description</label><input value={form.desc} onChange={upd("desc")} placeholder="e.g. Seedling purchase batch 1" /></div>
            <div className="form-group"><label>Amount (Tokens)</label><input value={form.amount} onChange={upd("amount")} type="number" placeholder="e.g. 500" /></div>
            <div className="form-group">
              <label>Category</label>
              <select value={form.cat} onChange={upd("cat")}>
                <option value="">Select...</option>
                <option>Equipment</option><option>Labor</option><option>Materials</option><option>Transport</option><option>Admin</option>
              </select>
            </div>
            <div className="form-group">
              <label>Receipt Hash</label>
              <input value={form.receipt} onChange={upd("receipt")} placeholder="IPFS hash" />
              <span className="input-hint">Store proof on IPFS for immutability</span>
            </div>
            <div className="form-actions">
              <button className="btn btn-secondary">Clear</button>
              <button className="btn btn-primary" onClick={() => toast("Expense recorded on ledger", "success")}>Record Expense</button>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Recent Expenses</div>
          <DataTable
            columns={[
              { key:"id",          label:"ID",      mono:true },
              { key:"description", label:"Description"        },
              { key:"amount",      label:"Amount",  render:(r) => <span className="text-gold">{fmt(r.amount)}</span> },
              { key:"date",        label:"Date",    mono:true  },
              { key:"status",      label:"Status",  render:(r) => <Badge type={r.status==="approved"?"green":"gold"}>{r.status}</Badge> },
            ]}
            data={expenses}
          />
        </div>
      </div>
    </div>
  );
}
